import java.util.Scanner;

public class SecureBufferHandling {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String input = scanner.nextLine();

        int bufferSize = 10; // Maximum buffer size
        char[] buffer = new char[bufferSize]; // Fixed size buffer

        // Copy the user input into the buffer with bounds checking
        for (int i = 0; i < input.length() && i < bufferSize; i++) {
            buffer[i] = input.charAt(i);
        }

        System.out.println("Buffer contents: " + new String(buffer).trim()); // Use trim to remove null characters

        scanner.close();
    }
}

### Explanation:
취약유형: Buffer Overflow
